const express = require('express');
const cors = require('cors');

const app = express();
app.use(cors());

// API route
app.get('/api/data', (req, res) => {
    res.json({
        message: "Hello from backend 🚀",
        time: new Date()
    });
});

// server start
app.listen(5000, () => {
    console.log("Server running on http://localhost:5000");
});